my $state = 'start';
while (1) {
    given ($state) {
        when ('start') {
            initialize();
            $state = 'process';
        }
        when ('process') {
            if (process_item()) {
                $state = 'finish';
            } else {
                $state = 'error';
            }
        }
        when ('error') {
            handle_error();
            $state = 'start';
        }
        when ('finish') {
            finalize();
            last;
        }
    }
}

my $iterator = sub {
    state @items = (1..10);
    state $index = 0;
    return if $index >= @items;
    return $items[$index++];
};

while (defined(my $item = $iterator->())) {
    process($item);
}

sub process_tree {
    my ($node, $depth) = @_;
    return if $depth > $max_depth;

    if ($node->{type} eq 'leaf') {
        process_leaf($node);
    } else {
        foreach my $child (@{$node->{children}}) {
            process_tree($child, $depth + 1);
        }
    }
}

foreach my $input (@inputs) {
    my $result = $input;

    STAGE: foreach my $stage (@pipeline) {
        eval {
            $result = $stage->process($result);
        };
        if ($@) {
            log_error("Stage failed: $@");
            next STAGE if $stage->{optional};
            last STAGE;
        }
    }

    push @outputs, $result if defined $result;
}

sub coroutine {
    my $state = shift;

    DISPATCH: {
        $state eq 'init' and do {
            initialize_data();
            $state = 'process';
            redo DISPATCH;
        };

        $state eq 'process' and do {
            return process_next() || 'done';
        };

        $state eq 'done' and do {
            cleanup();
            return undef;
        };
    }
}

while (my $event = get_next_event()) {
    given ($event->{type}) {
        when ('timer') {
            handle_timer($event);
            continue;
        }
        when ('input') {
            unless (validate_input($event)) {
                log_invalid_input($event);
                next;
            }
            process_input($event);
        }
        when ('shutdown') {
            cleanup_and_exit();
            last;
        }
        default {
            log_unknown_event($event);
        }
    }
}

my @workers = ();
for my $i (1..$num_workers) {
    push @workers, {
        id => $i,
        status => 'idle',
        task => undef
    };
}

while (@tasks || grep { $_->{status} eq 'busy' } @workers) {
    foreach my $worker (@workers) {
        if ($worker->{status} eq 'idle' && @tasks) {
            $worker->{task} = shift @tasks;
            $worker->{status} = 'busy';
        } elsif ($worker->{status} eq 'busy') {
            if (task_complete($worker->{task})) {
                finish_task($worker->{task});
                $worker->{status} = 'idle';
                $worker->{task} = undef;
            }
        }
    }
    sleep(0.1); # simulate time passage
}
